-- W1.6 questions batch 4920/9310 (10)

INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('heelevel3-6f0ba476-moex-00052', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-114-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'single_choice', '甲、乙為夫妻，無子女。甲之父母均已死亡，甲有兄弟丙、丁二人。甲生前曾向丙借款新臺幣（下 同）40萬元，尚未清償。甲死亡時，留有遺產200萬元。遺產分割時，丙可分得多少財產？', '["60萬元", "70萬元", "80萬元", "90萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:27+00:00", "source_pdf_sha1": "5520327b8010", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "222", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00053', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-114-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'single_choice', '甲男乙女於民國112年1月間結婚，甲於結婚前，有勞力所得新臺幣（下同）60萬元。下列關於 夫妻財產之敘述，何者正確？', '["設甲乙約定採共同財產制，甲勞力所得之60萬元，由甲乙分別共有", "設甲乙約定採分別財產制，甲勞力所得之60萬元，由甲乙分別共有", "設甲乙未約定夫妻財產制，甲勞力所得之60萬元，由甲乙公同共有", "設甲乙約定採勞力所得共同財產制，甲勞力所得之60萬元，由甲單獨所有"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:27+00:00", "source_pdf_sha1": "5520327b8010", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "222", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00054', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-114-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'single_choice', '未婚之甲女與乙男發生性關係後懷孕並產下丙。丙成年後找到乙，要求乙為認領。乙表示其生活 窮困，若丙願扶養，則乙願認領。下列敘述，何者正確？', '["認領後，如丙確有受扶養必要，乙有扶養能力，乙應扶養丙", "認領後，如乙確實無謀生能力但尚非無法維持生活，丙仍應扶養乙", "認領後，如乙確有受扶養必要，甲丙應共同扶養乙", "認領經雙方意思表示合致成立，乙所附條件為有效"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:27+00:00", "source_pdf_sha1": "5520327b8010", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "222", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00055', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-114-9b7ab1bb', 'sub-heelevel3-6f0ba476-02', NULL, 'single_choice', '甲乙為夫妻，生有A、B二子，並收養C為養女。乙於民國108年間死亡。今甲死亡，下列敘述， 何者正確？', '["A如對甲有重大之虐待或侮辱情事，經B及C共同表示A不得繼承；A則喪失其對甲之繼承權", "A及B於乙死亡後，否認C之繼承資格，並排除其對繼承財產之占有，C自知悉其得繼承之 時起2年間，得行使遺產酌給請求權", "B如有以詐欺或脅迫，使甲為關於繼承遺囑之情事，B則喪失其對甲之繼承權。但經甲宥恕者， 其繼承權不喪失", "甲如未立遺囑，C之應繼分為甲遺產之五分之一，A及B之應繼分各為甲遺產之五分之二"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:27+00:00", "source_pdf_sha1": "5520327b8010", "answer_pdf_sha1": "b00f4253350b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "222", "s": "0905", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00056', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-114-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'essay', '資本所得泛指運用資本（如土地、房產、股票、債券等）所產生的收益
或利得，通常包括：股利、利息、租金收入與資本利得等。資本所得課
稅方式，攸關資本形成，至關重要。請詳細說明我國所得稅法規定對於
營利事業獲配股利與境內居住之個人取得利息所得之課稅方式。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:28+00:00", "source_pdf_sha1": "9f0f79bb2d95", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "222", "s": "0704", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00057', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-114-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'essay', '請回答以下有關加值型及非加值型營業稅法的問題：
何謂在境內銷售貨物？出口是否屬於境內銷售貨物？（10分）
外國之事業、機關、團體、組織在境內無固定營業場所而有銷售勞務
者，營業稅之申報繳納規定為何？（15 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:28+00:00", "source_pdf_sha1": "9f0f79bb2d95", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "222", "s": "0704", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00058', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-114-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '稅捐稽徵法所稱「相當擔保」，係指相當於擔保稅款之下列擔保品，何者錯誤？', '["易於變價、無產權糾紛且能足額清償之土地或已辦妥建物所有權登記之房屋", "政府發行經規定可十足提供公務擔保之公債，按面額計值", "黃金，按九折計算", "上市或上櫃之有價證券，按七折計算"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:28+00:00", "source_pdf_sha1": "9f0f79bb2d95", "answer_pdf_sha1": "31f29bd093ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "222", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00059', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-114-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '依我國現行法律，下列敘述何者錯誤？', '["營利事業或個人依所得基本稅額條例規定計算之一般所得稅額高於或等於基本稅額者，該營利 事業或個人當年度應繳納之所得稅，應按所得稅法及其他相關法律規定計算認定。一般所得稅 額低於基本稅額者，其應繳納之所得稅，除按所得稅法及其他相關法律計算認定外，應另就基 本稅額與一般所得稅額之差額認定", "中華民國政府派駐國外工作人員在國外提供勞務之報酬，為中華民國來源所得", "自中華民國境內居住之個人所取得之利息，為中華民國來源所得", "非中華民國境內居住之個人，於一課稅年度內在中華民國境內居留 61 天，其自中華民國境外 僱主所取得之在中華民國境內提供勞務之報酬，為中華民國來源所得"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:28+00:00", "source_pdf_sha1": "9f0f79bb2d95", "answer_pdf_sha1": "31f29bd093ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "222", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00060', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-114-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '所得稅法第4條之4第1項規定，個人及營利事業交易於中華民國105年1月1日以後取得之房 屋、房屋及其坐落基地或依法得核發建造執照之土地（以下合稱房屋、土地），其交易所得應依所 得稅法第14條之4至第14條之8及第24條之5規定課徵所得稅。下列敘述何者錯誤？', '["某自然人於中華民國105年1月1日以後取得以設定地上權方式之房屋使用權及其坐落基地， 其交易視同所得稅法第4條之4第1項之房屋、土地交易", "某營利事業於中華民國105年1月1日以後取得預售屋及其坐落基地，其交易視同所得稅法第 4條之4第1項之房屋、土地交易", "某自然人交易其直接或間接持有股份或出資額過半數之我國興櫃公司股份，該公司股權價值百 分之五十以上係由中華民國境內之房屋、土地所構成，該交易視同所得稅法第4條之4第1項 房屋、土地交易", "所得稅法第4條之4第1項所定房屋之範圍，不包括依農業發展條例申請興建之農舍"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:28+00:00", "source_pdf_sha1": "9f0f79bb2d95", "answer_pdf_sha1": "31f29bd093ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "222", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('heelevel3-6f0ba476-moex-00061', 'heelevel3-6f0ba476', 'heelevel3-6f0ba476-moex-114-9bdab6d6', 'sub-heelevel3-6f0ba476-03', NULL, 'single_choice', '薪資所得之計算，以在職務上或工作上取得之各種薪資收入，減除薪資所得特別扣除額後之餘額 為所得額，但與提供勞務直接相關且由所得人負擔之「特定種類必要費用」合計金額超過該扣除 額者，得檢附相關證明文件核實自薪資收入中減除該必要費用，以其餘額為所得額。「特定種類必 要費用」不包括下列何者？', '["職業專用服裝費", "進修訓練費", "職業上通勤支出", "職業上工具支出"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:28+00:00", "source_pdf_sha1": "9f0f79bb2d95", "answer_pdf_sha1": "31f29bd093ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "222", "s": "0704", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅行政"}'::jsonb, NULL)
